INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-jam-waktu-sholat'), 1, 'Hidupkan WiFi', 'Pastikan WiFi di smartphone atau komputer sudah menyala.', NULL);
INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-jam-waktu-sholat'), 2, 'Hubungkan ke WiFi JWS', 'Cari dan hubungkan perangkat ke jaringan WiFi jam waktu sholat.', NULL);
INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-jam-waktu-sholat'), 3, 'Masukkan Password', 'Gunakan password standar perangkat.', 'unaproject28');
INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-jam-waktu-sholat'), 4, 'Akses Menu Setting', 'Buka browser dan masuk ke menu pengaturan jam waktu sholat.', NULL);
INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-jam-waktu-sholat'), 5, 'Atur Parameter', 'Sesuaikan parameter seperti kota, zona waktu, iqomah, dan pengaturan lain sesuai kebutuhan.', NULL);
INSERT INTO tutorials (slug, title, category, short_description, video_url, is_active, order_index)
INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-running-text-jws'), 1, 'Download Aplikasi', 'Download aplikasi LedART melalui Google Play Store.', NULL);
INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-running-text-jws'), 2, 'Hubungkan WiFi', 'Hubungkan perangkat ke WiFi running text. Biasanya diawali dengan nama jaringan HD_W02.', NULL);
INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-running-text-jws'), 3, 'Masukkan Password', 'Gunakan password running text.', 'unaproject28');
INSERT INTO tutorial_steps (tutorial_id, step_number, title, description, highlight) VALUES ((SELECT id FROM tutorials WHERE slug = 'setting-running-text-jws'), 4, 'Konfigurasi Text', 'Setelah terhubung, mulai atur teks yang akan ditampilkan pada panel running text.', NULL);
INSERT INTO order_steps (step_number, title, description, icon_name, is_active, order_index) VALUES ('01', 'Pilih Produk', 'Lihat katalog produk dan tentukan jenis kebutuhan awal, misalnya jam waktu sholat, running text LED, atau produk custom.', 'default', TRUE, 1);
INSERT INTO order_steps (step_number, title, description, icon_name, is_active, order_index) VALUES ('02', 'Konsultasi Kebutuhan', 'Diskusikan lokasi pemasangan, ukuran, fitur, warna tampilan, serta kebutuhan informasi yang ingin ditampilkan.', 'default', TRUE, 2);
INSERT INTO order_steps (step_number, title, description, icon_name, is_active, order_index) VALUES ('03', 'Konfirmasi Ukuran dan Harga', 'UNA Project membantu menghitung estimasi harga berdasarkan ukuran, bahan, fitur, dan kebutuhan pemasangan.', 'default', TRUE, 3);
INSERT INTO order_steps (step_number, title, description, icon_name, is_active, order_index) VALUES ('04', 'Pembayaran DP', 'Setelah spesifikasi disepakati, customer melakukan pembayaran DP sebagai tanda mulai proses produksi.', 'default', TRUE, 4);
INSERT INTO order_steps (step_number, title, description, icon_name, is_active, order_index) VALUES ('05', 'Proses Produksi', 'Produk dibuat sesuai spesifikasi yang sudah disepakati. Lama produksi menyesuaikan tingkat custom dan antrean pekerjaan.', 'default', TRUE, 5);
INSERT INTO order_steps (step_number, title, description, icon_name, is_active, order_index) VALUES ('06', 'Instalasi atau Pengiriman', 'Produk dikirim atau dipasang sesuai kesepakatan. Untuk produk tertentu, proses setting awal dapat dibantu.', 'default', TRUE, 6);
INSERT INTO order_steps (step_number, title, description, icon_name, is_active, order_index) VALUES ('07', 'Garansi dan After-Sales', 'Setelah produk diterima, customer tetap bisa berkonsultasi untuk penggunaan, setting, dan kendala dasar.', 'default', TRUE, 7);
INSERT INTO whatsapp_templates (template_name, category, message_pattern, is_default, is_active) VALUES ('konsultasi_umum', 'Konsultasi', 'Halo UNA Project, saya ingin konsultasi produk UNA Project.', TRUE, TRUE) ON CONFLICT (template_name) DO UPDATE SET category = EXCLUDED.category, message_pattern = EXCLUDED.message_pattern, is_default = EXCLUDED.is_default, is_active = EXCLUDED.is_active;
INSERT INTO whatsapp_templates (template_name, category, message_pattern, is_default, is_active) VALUES ('konsultasi_produk', 'Produk', 'Halo UNA Project, saya ingin konsultasi produk {product_name}.', TRUE, TRUE) ON CONFLICT (template_name) DO UPDATE SET category = EXCLUDED.category, message_pattern = EXCLUDED.message_pattern, is_default = EXCLUDED.is_default, is_active = EXCLUDED.is_active;
INSERT INTO whatsapp_templates (template_name, category, message_pattern, is_default, is_active) VALUES ('info_garansi', 'Dukungan', 'Halo UNA Project, saya ingin tanya garansi produk.', TRUE, TRUE) ON CONFLICT (template_name) DO UPDATE SET category = EXCLUDED.category, message_pattern = EXCLUDED.message_pattern, is_default = EXCLUDED.is_default, is_active = EXCLUDED.is_active;
